import React, { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';

const Profile = () => {
  const { currentUser } = useAuth();
  const [activeTab, setActiveTab] = useState('profile');
  const [userData, setUserData] = useState(null);
  const [journalEntries, setJournalEntries] = useState([]);
  const [stats, setStats] = useState({ entries: 0, streak: 0, daysActive: 0 });
  const [loading, setLoading] = useState(true);

  // Fetch real user data
  useEffect(() => {
    fetchUserData();
    fetchJournalEntries();
    fetchUserStats();
  }, []);

  const fetchUserData = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch('http://localhost:3001/api/users/me', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      const data = await response.json();
      if (data.success) {
        setUserData(data.data);
      }
    } catch (error) {
      console.error('Error fetching user data:', error);
    }
  };

  const fetchJournalEntries = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch('http://localhost:3001/api/journals', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      const data = await response.json();
      if (data.success) {
        setJournalEntries(data.data || []);
      }
    } catch (error) {
      console.error('Error fetching journals:', error);
    }
  };

  const fetchUserStats = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch('http://localhost:3001/api/users/stats', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      const data = await response.json();
      if (data.success) {
        setStats(data.data);
      }
    } catch (error) {
      console.error('Error fetching stats:', error);
    } finally {
      setLoading(false);
    }
  };

  const moodIcons = {
    happy: '😊',
    sad: '😔',
    anxious: '😰',
    angry: '😠',
    tired: '😴',
    neutral: '😐',
    excited: '🤩'
  };

  if (loading) {
    return (
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
        <div className="text-center">Loading profile...</div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
      <div className="bg-white dark:bg-gray-800 shadow rounded-lg overflow-hidden transition-colors duration-300">
        {/* Profile Header */}
        <div className="px-6 py-8 bg-gradient-to-r from-lavender-500 to-seafoam-500">
          <div className="flex items-center">
            <img
              className="h-24 w-24 rounded-full border-4 border-white"
              src={userData?.avatar || 'https://static.vecteezy.com/system/resources/previews/008/149/271/large_2x/user-icon-for-graphic-design-logo-website-social-media-mobile-app-ui-illustration-free-vector.jpg'}
              alt={userData?.username}
            />
            <div className="ml-6">
              <h1 className="text-3xl font-bold text-white">
                {userData?.firstName} {userData?.lastName}
              </h1>
              <p className="text-lavender-100">@{userData?.username}</p>
              <p className="text-white mt-2">{userData?.bio || 'No bio yet'}</p>
            </div>
          </div>
        </div>

        {/* Navigation Tabs */}
        <div className="border-b border-gray-200 dark:border-gray-700 transition-colors duration-300">
          <nav className="flex -mb-px">
            {['profile', 'journal', 'settings'].map((tab) => (
              <button
                key={tab}
                onClick={() => setActiveTab(tab)}
                className={`ml-8 first:ml-0 py-4 px-1 text-sm font-medium border-b-2 ${
                  activeTab === tab
                    ? 'border-lavender-500 text-lavender-600 dark:text-lavender-400'
                    : 'border-transparent text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-300 hover:border-gray-300 dark:hover:border-gray-600'
                } transition-colors duration-200 capitalize`}
              >
                {tab}
              </button>
            ))}
          </nav>
        </div>

        {/* Tab Content */}
        <div className="p-6">
          {activeTab === 'profile' && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <h2 className="text-lg font-medium text-gray-900 dark:text-white mb-4 transition-colors duration-300">
                  Personal Information
                </h2>
                <div className="space-y-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 transition-colors duration-300">
                      Username
                    </label>
                    <p className="mt-1 text-gray-900 dark:text-white transition-colors duration-300">
                      {userData?.username}
                    </p>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 transition-colors duration-300">
                      Email
                    </label>
                    <p className="mt-1 text-gray-900 dark:text-white transition-colors duration-300">
                      {userData?.email}
                    </p>
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 transition-colors duration-300">
                      Phone
                    </label>
                    <p className="mt-1 text-gray-900 dark:text-white transition-colors duration-300">
                      {userData?.phone || 'Not provided'}
                    </p>
                  </div>
                </div>
              </div>
              <div>
                <h2 className="text-lg font-medium text-gray-900 dark:text-white mb-4 transition-colors duration-300">
                  Recent Activity
                </h2>
                <div className="bg-gray-50 dark:bg-gray-700 rounded-lg p-4 transition-colors duration-300">
                  <div className="flex items-center justify-between mb-3">
                    <span className="text-sm text-gray-600 dark:text-gray-300 transition-colors duration-300">
                      Journal Entries
                    </span>
                    <span className="text-lg font-semibold text-lavender-600 dark:text-lavender-400 transition-colors duration-300">
                      {stats.entries || 0}
                    </span>
                  </div>
                  <div className="flex items-center justify-between mb-3">
                    <span className="text-sm text-gray-600 dark:text-gray-300 transition-colors duration-300">
                      Days Active
                    </span>
                    <span className="text-lg font-semibold text-lavender-600 dark:text-lavender-400 transition-colors duration-300">
                      {stats.daysActive || 0}
                    </span>
                  </div>
                  <div className="flex items-center justify-between">
                    <span className="text-sm text-gray-600 dark:text-gray-300 transition-colors duration-300">
                      Current Streak
                    </span>
                    <span className="text-lg font-semibold text-lavender-600 dark:text-lavender-400 transition-colors duration-300">
                      {stats.streak || 0} days
                    </span>
                  </div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'journal' && (
            <div>
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-lg font-medium text-gray-900 dark:text-white transition-colors duration-300">
                  Journal Entries
                </h2>
                <button className="bg-lavender-600 hover:bg-lavender-700 text-white px-4 py-2 rounded-md transition-colors duration-200">
                  New Entry
                </button>
              </div>
              <div className="space-y-4">
                {journalEntries.length === 0 ? (
                  <p className="text-gray-500 dark:text-gray-400">No journal entries yet.</p>
                ) : (
                  journalEntries.map((entry) => (
                    <div key={entry._id} className="bg-white dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-lg p-4 transition-colors duration-300">
                      <div className="flex items-center justify-between mb-2">
                        <div className="flex items-center">
                          <span className="text-2xl mr-2">{moodIcons[entry.mood]}</span>
                          <h3 className="font-medium text-gray-900 dark:text-white transition-colors duration-300">
                            {entry.title}
                          </h3>
                        </div>
                        <span className="text-sm text-gray-500 dark:text-gray-400 transition-colors duration-300">
                          {new Date(entry.createdAt).toLocaleDateString()}
                        </span>
                      </div>
                      <p className="text-gray-600 dark:text-gray-300 transition-colors duration-300">
                        {entry.content}
                      </p>
                    </div>
                  ))
                )}
              </div>
            </div>
          )}

          {/* Settings tab remains the same */}
        </div>
      </div>
    </div>
  );
};

export default Profile;
